/**************** MQResistanceCalculation ****************************************
Input: raw_adc - raw value read from adc, which represents the voltage
Output: the calculated sensor resistance
Remarks: The sensor and the load resistor forms a voltage divider. Given
the voltage across the load resistor and its resistance, the resistance of the sensor
could be derived.
*******************************************************************************/
float MQResistanceCalculation(int raw_adc)
{
  float r;
  r = ((RL_VALUE * (1023 - raw_adc) / raw_adc));
  return r;
}

/*************************** MQRead *******************************************
Input: mq_pin - analog channel
Output: Rs of the sensor
Remarks: This function uses MQResistanceCalculation to calculate the sensor resistance (Rs).
The Rs changes as the sensor is in the different concentration of the target gas.
The sample times and the time interval between samples could be configured by changing macros.
*******************************************************************************/
float MQRead(int mq_pin)
{
  int i;
  float rs = 0;

  for (i = 0; i < READ_SAMPLE_TIMES; i++) {
    rs += MQResistanceCalculation(analogRead(mq_pin));
    delay(READ_SAMPLE_INTERVAL);
  }

  rs = rs / READ_SAMPLE_TIMES;
  return rs;
}

/*************************** MQGetPercentage ********************************
Input: rs_ro_ratio - Rs divided by Ro
pcurve - pointer to the curve of the target gas
Output: ppm of the target gas
Remarks: By using the slope and a point of the line. The x (logarithmic value of ppm)
of the line could be derived if y (rs_ro_ratio) is provided. As it is a logarithmic coordinate,
power of 10 is used to convert the result to non-logarithmic value.
*******************************************************************************/
int MQGetPercentage(float rs_ro_ratio, float *pcurve)
{
  return pow(10, pcurve[1] + pcurve[0] * log10(rs_ro_ratio));
}

/*************************** MQCalibration **************************************
Input: mq_pin - analog channel
Output: Ro of the sensor
Remarks: This function assumes that the sensor is in clean air.
It uses MQResistanceCalculation to calculate the sensor resistance in clean air
and then divides it with RO_CLEAN_AIR_FACTOR.
RO_CLEAN_AIR_FACTOR is about 10, which differs slightly between different sensors.
*******************************************************************************/
float MQCalibration(int mq_pin, float *pcurve)
{
  int i;
  float ro;
  float val = 0;

  for (i = 0; i < CALIBARAION_SAMPLE_TIMES; i++) { // take multiple samples
    val += MQResistanceCalculation(analogRead(mq_pin));
    delay(CALIBRATION_SAMPLE_INTERVAL);
  }

  val = val / CALIBARAION_SAMPLE_TIMES; // calculate the average value

  ro = val / pow(10, ((log10(400) - CO2Curve[1]) / CO2Curve[0]));
  // ro = val / CLEANAIRRS_RO;
  // calculate ro from rs assuming 400 ppm of CO2

  return ro;
}

