/*
Liquid flow rate sensor - DIYhacking.com Arvind Sanjeev

Measure the liquid/water flow rate using this code.
Connect Vcc and Gnd of sensor to arduino, and the signal line to arduino digital pin 2.
*/

byte statusLed = 13;

byte sensorInterrupt = 2;
// Yuankai: the return value should be the pin value. Or we can use the
// recommended code: attachInterrupt(digitalPinToInterrupt(pin), ISR, mode).
byte sensorPin = 2;

// The hall-effect flow sensor outputs approximately 4.5 pulses per second per
// litre/minute of flow.
float calibrationFactor = 7.4;

volatile byte pulseCount;

float flowRate;
unsigned int flowMilliLitres;
unsigned long totalMilliLitres;

unsigned long oldTime;

void setup()
{
  // Initialize a serial connection for reporting values to the host
  Serial.begin(9600);

  // Set up the status LED line as an output
  pinMode(statusLed, OUTPUT);
  digitalWrite(statusLed, HIGH); // We have an active-low LED attached

  pinMode(sensorPin, INPUT);
  digitalWrite(sensorPin, HIGH);

  pulseCount = 0;
  flowRate = 0.0;
  flowMilliLitres = 0;
  totalMilliLitres = 0;
  oldTime = 0;

  // The Hall-effect sensor is connected to pin 2 which uses interrupt 0.
  // Configured to trigger on a FALLING state change (transition from HIGH to LOW)
  attachInterrupt(sensorInterrupt, pulseCounter, FALLING);

  // Yuankai: or use the alternative recommended way to program:
  // attachInterrupt(digitalPinToInterrupt(sensorPin), pulseCounter, FALLING);
}

/**
 * Main program loop
 */
void loop()
{
  if ((millis() - oldTime) > 1000) // Only process counters once per second
  {
    // Disable the interrupt while calculating flow rate and sending the value to the host
    detachInterrupt(sensorInterrupt);

    // Scale the output based on time since last execution and apply calibrationFactor.
    flowRate = ((1000.0 / (millis() - oldTime)) * pulseCount) / calibrationFactor;

    oldTime = millis();

    // Convert flow rate (L/min) to millilitres passed in 1 second
    flowMilliLitres = (flowRate / 60) * 1000;

    // Add the millilitres passed in this second to the cumulative total
    totalMilliLitres += flowMilliLitres;

    // Print the flow rate for this second in litres / minute
    Serial.print("Flow rate: ");
    Serial.print(int(flowRate));  // Print the integer part of the variable
    Serial.print("L/min");
    Serial.print("\t");          // Print tab space

    // Print the cumulative total of litres flowed since starting
    Serial.print("Output Liquid Quantity: ");
    Serial.print(totalMilliLitres);
    Serial.println("mL");
    Serial.print("\t");          // Print tab space
    Serial.print(totalMilliLitres / 1000);
    Serial.print("L");

    // Reset the pulse counter so we can start incrementing again
    pulseCount = 0;

    // Enable the interrupt again now that we've finished sending output
    attachInterrupt(sensorInterrupt, pulseCounter, FALLING);

    // Yuankai: or use the alternative recommended way to program:
    // attachInterrupt(digitalPinToInterrupt(sensorPin), pulseCounter, FALLING);
  }
}

